mapper.select:
SELECT DISTINCT d.id
FROM rag_document d
LEFT JOIN rag_document_permission dp ON d.id = dp.document_id
WHERE d.deleted = 0
AND (
    d.user_id = #{userId}
    OR dp.user_id = #{userId}
    OR dp.role_id IN (
        SELECT ur.role_id
        FROM sys_user_role ur
        WHERE ur.user_id = #{userId} AND ur.deleted = 0
    )
)
